INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 7001, 1, 0, "2015/12/17 15:00:00", 1, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 7, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 7002, 1, 0, "2015/12/17 15:00:00", 1, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 7, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 7003, 1, 0, "2015/12/17 15:00:00", 1, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 7, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 10001, 1, 0, "2015/12/17 15:00:00", 1, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 10, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 10002, 1, 0, "2015/12/17 15:00:00", 1, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 10, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 10003, 1, 0, "2015/12/17 15:00:00", 1, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 10, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 10004, 1, 0, "2015/12/17 15:00:00", 2, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 10, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 12001, 1, 0, "2015/12/17 15:00:00", 1, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "ペコリーヌ", 1, 0.0, -416.5, 105801, "2030/12/17 14:59:59", 12, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 13001, 1, 0, "2015/12/17 15:00:00", 1, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 13, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 13002, 1, 0, "2015/12/17 15:00:00", 1, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 13, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 13003, 1, 0, "2015/12/17 15:00:00", 2, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 13, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 13004, 1, 0, "2015/12/17 15:00:00", 1, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 13, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 14001, 1, 0, "2015/12/17 15:00:00", 1, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 14, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 14002, 1, 0, "2015/12/17 15:00:00", 2, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 14, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 14003, 1, 0, "2015/12/17 15:00:00", 1, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 14, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 14004, 1, 0, "2015/12/17 15:00:00", 1, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 14, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 15001, 1, 0, "2015/12/17 15:00:00", 1, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "コッコロ", 1, 0.0, -470.0, 105901, "2030/12/17 14:59:59", 15, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 16001, 1, 0, "2015/12/17 15:00:00", 2, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 16, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 16002, 1, 0, "2015/12/17 15:00:00", 1, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 16, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 16003, 1, 0, "2015/12/17 15:00:00", 1, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 16, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 16004, 1, 0, "2015/12/17 15:00:00", 1, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 16, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 17002, 1, 0, "2015/12/17 15:00:00", 1, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 17, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 17004, 1, 0, "2015/12/17 15:00:00", 1, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 25, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 17005, 1, 0, "2015/12/17 15:00:00", 1, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 25, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 17006, 1, 0, "2015/12/17 15:00:00", 2, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 25, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 17007, 1, 0, "2015/12/17 15:00:00", 1, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 25, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 18001, 1, 0, "2015/12/17 15:00:00", 1, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "カリン", 1, 0.0, -363.0, 190801, "2030/12/17 14:59:59", 18, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 18002, 1, 0, "2015/12/17 15:00:00", 1, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "カリン", 2, 0.0, -363.0, 190801, "2030/12/17 14:59:59", 18, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 19001, 1, 0, "2015/12/17 15:00:00", 1, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "カリン", 3, 0.0, -470.0, 190801, "2030/12/17 14:59:59", 19, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 19002, 1, 0, "2015/12/17 15:00:00", 1, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "カリン", 4, 0.0, -470.0, 190801, "2030/12/17 14:59:59", 19, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 20001, 1, 0, "2015/12/17 15:00:00", 1, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "カリン", 5, 0.0, -470.0, 190801, "2030/12/17 14:59:59", 20, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 20002, 1, 0, "2015/12/17 15:00:00", 1, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "カリン", 6, 0.0, -470.0, 190801, "2030/12/17 14:59:59", 20, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 21001, 1, 0, "2015/12/17 15:00:00", 1, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 21, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 21002, 1, 0, "2015/12/17 15:00:00", 1, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 21, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 21003, 1, 0, "2015/12/17 15:00:00", 2, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 21, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 21004, 1, 0, "2015/12/17 15:00:00", 1, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 21, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 22001, 1, 0, "2015/12/17 15:00:00", 1, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "カリン", 1, 0.0, -430.0, 190801, "2030/12/17 14:59:59", 22, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 22002, 1, 0, "2015/12/17 15:00:00", 1, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "カリン", 2, 0.0, -430.0, 190801, "2030/12/17 14:59:59", 22, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 23001, 1, 0, "2015/12/17 15:00:00", 1, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "カリン", 3, 0.0, -430.0, 190801, "2030/12/17 14:59:59", 23, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 23002, 1, 0, "2015/12/17 15:00:00", 1, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "カリン", 4, 0.0, -430.0, 190801, "2030/12/17 14:59:59", 23, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24001, 2, 10011, "2019/01/31 12:00:00", 1, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "エリコ（バレンタイン）", 1, 4.08, -385.0, 109001, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24002, 2, 10011, "2019/01/31 12:00:00", 1, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "エリコ（バレンタイン）", 2, 5.0, -385.0, 109001, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24003, 2, 10011, "2019/01/31 12:00:00", 1, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "エリコ（バレンタイン）", 3, 10.11, -385.0, 109001, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24004, 2, 10011, "2019/01/31 12:00:00", 1, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "エリコ（バレンタイン）", 4, 4.0, -385.0, 109001, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24005, 2, 10011, "2019/01/31 12:00:00", 1, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "エリコ（バレンタイン）", 5, 6.0, -385.0, 109001, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24006, 1, 10011, "2019/01/31 12:00:00", 1, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "エリコ（バレンタイン）", 6, 0.0, 0.0, 109002, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24007, 1, 10011, "2019/01/31 12:00:00", 1, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "エリコ（バレンタイン）", 7, 0.0, 0.0, 109002, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24008, 1, 10011, "2019/01/31 12:00:00", 1, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "エリコ（バレンタイン）", 8, 0.0, 0.0, 109002, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24009, 1, 10011, "2019/01/31 12:00:00", 1, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "エリコ（バレンタイン）", 9, 0.0, 0.0, 109002, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24010, 1, 10011, "2019/01/31 12:00:00", 1, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "エリコ（バレンタイン）", 10, 0.0, 0.0, 109002, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24011, 2, 10011, "2019/01/31 12:00:00", 1, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "シズル（バレンタイン）", 1, 2.12, -385.0, 109101, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24012, 2, 10011, "2019/01/31 12:00:00", 5, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "シズル（バレンタイン）", 2, 4.19, -385.0, 109101, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24013, 4, 10011, "2019/01/31 12:00:00", 2, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "シズル（バレンタイン）", 3, 2.3, -385.0, 109101, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24014, 1, 10011, "2019/01/31 12:00:00", 1, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "シズル（バレンタイン）", 4, 0.0, 0.0, 109102, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24015, 2, 10011, "2019/01/31 12:00:00", 5, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "シズル（バレンタイン）", 5, 5.23, -385.0, 109101, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24016, 1, 10011, "2019/01/31 12:00:00", 1, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "シズル（バレンタイン）", 6, 0.0, 0.0, 109102, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (8.0, 24017, 2, 10011, "2019/01/31 12:00:00", 1, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "シズル（バレンタイン）", 7, 5.01, -385.0, 109101, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24018, 1, 10011, "2019/01/31 12:00:00", 1, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "シズル（バレンタイン）", 8, 0.0, 0.0, 109102, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24019, 1, 10011, "2019/01/31 12:00:00", 1, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "シズル（バレンタイン）", 9, 0.0, 0.0, 109102, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 24020, 1, 10011, "2019/01/31 12:00:00", 1, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "シズル（バレンタイン）", 10, 0.0, 0.0, 109102, "2030/12/17 14:59:59", 24, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 26001, 1, 0, "2015/12/17 15:00:00", 2, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 26, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 26002, 1, 0, "2015/12/17 15:00:00", 1, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 26, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 26003, 1, 0, "2015/12/17 15:00:00", 1, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 26, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 26004, 1, 0, "2015/12/17 15:00:00", 1, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 26, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 27001, 1, 0, "2015/12/17 15:00:00", 2, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 27, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 27002, 1, 0, "2015/12/17 15:00:00", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 27, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 27003, 1, 0, "2015/12/17 15:00:00", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 27, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 27004, 1, 0, "2015/12/17 15:00:00", 1, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 27, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 28001, 1, 0, "2019/09/24 15:00:00", 1, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "カリン", 1, 0.0, -363.0, 190801, "2030/12/17 14:59:59", 28, 0);
