INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 29001, 1, 0, "2019/09/24 15:00:00", 1, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "カリン", 3, 0.0, -409.0, 190801, "2030/12/17 14:59:59", 29, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 29002, 1, 0, "2019/09/24 15:00:00", 1, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "カリン", 4, 0.0, -409.0, 190801, "2030/12/17 14:59:59", 29, 0);
