INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 31001, 1, 0, "2019/10/31 12:00:00", 1, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", "カリン", 7, 0.0, -409.0, 190801, "2030/12/17 14:59:59", 31, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 31002, 1, 0, "2019/10/31 12:00:00", 1, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "カリン", 8, 0.0, -409.0, 190801, "2030/12/17 14:59:59", 31, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 32001, 1, 0, "2019/12/20 5:00:00", 1, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "カリン", 1, 0.0, -409.0, 190801, "2020/01/04 4:59:59", 32, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 32002, 1, 0, "2019/12/20 5:00:00", 1, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 2, 0.0, -409.0, 190801, "2020/01/04 4:59:59", 32, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 33001, 1, 0, "2019/12/20 5:00:00", 1, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", "カリン", 3, 0.0, -409.0, 190801, "2020/01/04 4:59:59", 33, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 33002, 1, 0, "2019/12/20 5:00:00", 1, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 4, 0.0, -409.0, 190801, "2020/01/04 4:59:59", 33, 0);
