INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 34002, 1, 0, "2020/01/04 5:00:00", 1, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "カリン", 6, 0.0, -409.0, 190801, "2020/01/10 11:59:59", 34, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 38001, 2, 0, "2015/12/17 15:00:00", 1, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "ペコリーヌ", 1, 5.3, -458.0, 105801, "2030/12/17 14:59:59", 38, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 38002, 2, 0, "2015/12/17 15:00:00", 1, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "ペコリーヌ", 2, 6.5, -458.0, 105801, "2030/12/17 14:59:59", 38, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (9999.0, 39005, 3, 0, "2020/04/01", 3, "", "ペコリーヌ", 0, 0.0, 9999.0, 105801, "2020/04/08 23:59:59", 39, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 40001, 1, 0, "2015/12/17 15:00:00", 1, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "カリン", 2, 0.0, -430.0, 190801, "2030/12/17 14:59:59", 40, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 41001, 1, 0, "2015/12/17 15:00:00", 1, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "シェフィ", 1, 0.0, -363.0, 106401, "2030/12/17 14:59:59", 41, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 41002, 1, 0, "2015/12/17 15:00:00", 1, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 41, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 41003, 1, 0, "2015/12/17 15:00:00", 1, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 41, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 41004, 1, 0, "2015/12/17 15:00:00", 1, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 41, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 42001, 1, 0, "2015/12/17 15:00:00", 1, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "コッコロ", 1, 0.0, -416.5, 105901, "2030/12/17 14:59:59", 42, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 42002, 1, 0, "2015/12/17 15:00:00", 1, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "シェフィ", 1, 0.0, -416.5, 106401, "2030/12/17 14:59:59", 42, 2104010);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 42003, 1, 0, "2015/12/17 15:00:00", 1, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "ペコリーヌ", 1, 0.0, -416.5, 105801, "2030/12/17 14:59:59", 42, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 42004, 1, 0, "2015/12/17 15:00:00", 1, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "キャル", 1, 0.0, -416.5, 106001, "2030/12/17 14:59:59", 42, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43001, 1, 0, "2015/12/17 15:00:00", 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "ペコリーヌ", 1, 0.0, -363.0, 105801, "2030/12/17 14:59:59", 43, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43002, 1, 0, "2015/12/17 15:00:00", 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "コッコロ", 1, 0.0, -363.0, 105901, "2030/12/17 14:59:59", 43, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43003, 1, 0, "2015/12/17 15:00:00", 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "キャル", 1, 0.0, -363.0, 106001, "2030/12/17 14:59:59", 43, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43004, 1, 0, "2015/12/17 15:00:00", 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "アメス", 1, 0.0, -416.5, 123001, "2030/12/17 14:59:59", 44, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43005, 1, 0, "2015/12/17 15:00:00", 1, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "アメス", 2, 0.0, -416.5, 123001, "2030/12/17 14:59:59", 44, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 43006, 2, 0, "2015/12/17 15:00:00", 1, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "アメス", 3, 5.79, -416.5, 123001, "2030/12/17 14:59:59", 45, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 46001, 1, 0, "2015/12/17 15:00:00", 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "アメス", 1, 0.0, -371.5, 123001, "2030/12/17 14:59:59", 46, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 47001, 2, 0, "2015/12/17 15:00:00", 2, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "シズル", 1, 0.0, -416.5, 104901, "2030/12/17 14:59:59", 47, 0);
INSERT INTO `v1_bd7bf6e220bd2598118016278330baf21d46c94f1807b908ab403231a1296a3f` VALUES (0.0, 47002, 2, 0, "2015/12/17 15:00:00", 1, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "リノ", 1, 9.32, -416.5, 101101, "2030/12/17 14:59:59", 47, 0);
